import os
import sys

def parse_command(user_input):
    """Parse user input into command and arguments"""
    parts = user_input.strip().split()
    if not parts:
        return None, []
    command = parts[0]
    args = parts[1:]
    return command, args

def execute_command(command, args):
    """Execute the parsed command"""
    built_in_commands = {
        'ls': lambda a: os.listdir(a[0] if a else '.'),
        'pwd': lambda a: os.getcwd(),
        'echo': lambda a: ' '.join(a),
        'cd': lambda a: os.chdir(a[0] if a else os.path.expanduser('~'))
    }

    if command in built_in_commands:
        try:
            result = built_in_commands[command](args)
            print(result)
        except Exception as e:
            print(f"Error: {e}")
    else:
        print(f"Command not found: {command}")

def shell_loop():
    """Main shell loop - simulates command interpreter"""
    print("Simple Shell v1.0 - Type 'exit' to quit")

    while True:
        user_input = input(f"{os.getcwd()}$ ")

        if user_input.lower() == 'exit':
            break

        command, args = parse_command(user_input)

        if command:
            execute_command(command, args)

if __name__ == "__main__":
    shell_loop()

#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>

int main() {
    // File descriptor - returned by open() system call
    int fd;

    // System call to open a file (transitions to kernel mode)
    fd = open("example.txt", O_RDONLY);

    if (fd == -1) {
        perror("Error opening file");
        return 1;
    }

    // Buffer for reading file content
    char buffer[100];
    ssize_t bytes_read;

    // System call to read from file
    bytes_read = read(fd, buffer, sizeof(buffer) - 1);

    if (bytes_read == -1) {
        perror("Error reading file");
        close(fd);
        return 1;
    }

    // Null terminate and print
    buffer[bytes_read] = '\0';
    printf("File content: %s\n", buffer);

    // System call to close file
    close(fd);

    return 0;
}
